@namespace Lumeo
@inject IComponentInteropService Interop
@implements IAsyncDisposable

@if (!Overflow)
{
    <div role="toolbar"
         id="@_toolbarId"
         aria-orientation="@OrientationStr"
         tabindex="0"
         class="@CssClass"
         @onkeydown="HandleKeyDown"
         @attributes="AdditionalAttributes">
        @ChildContent
    </div>
}
else
{
    <div role="toolbar"
         id="@_toolbarId"
         aria-orientation="@OrientationStr"
         tabindex="0"
         class="@CssClassOverflow"
         @onkeydown="HandleKeyDown"
         @attributes="AdditionalAttributes">
        <CascadingValue Value="_overflowCtx" IsFixed="false">
            @ChildContent
        </CascadingValue>

        @if (_overflowCtx.VisibleCount >= 0 && _overflowCtx.VisibleCount < _overflowCtx.TotalCount)
        {
            <div class="shrink-0" data-toolbar-overflow-trigger>
                <DropdownMenu @bind-Open="_overflowOpen">
                    <DropdownMenuTrigger>
                        <Button Variant="Button.ButtonVariant.Ghost"
                                Size="Button.ButtonSize.Sm"
                                aria-label="@(OverflowLabel ?? "More")">
                            <SvgGlyph Svg="@(LumeoIcons.Ellipsis)" class="h-4 w-4" />
                        </Button>
                    </DropdownMenuTrigger>
                    <DropdownMenuContent Align="Lumeo.Align.End">
                        <CascadingValue Value="_dropdownCtx" IsFixed="false">
                            @ChildContent
                        </CascadingValue>
                    </DropdownMenuContent>
                </DropdownMenu>
            </div>
        }
    </div>
}

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    /// <summary>
    /// When true the toolbar collapses items that don't fit into a trailing "⋯" dropdown.
    /// Use <see cref="VisibleCount"/> to control how many items are shown inline, or leave
    /// it at -1 (the default) to let the toolbar auto-measure via <c>ResizeObserver</c>.
    /// </summary>
    [Parameter] public bool Overflow { get; set; }

    /// <summary>
    /// Number of leading items to show inline when <see cref="Overflow"/> is true.
    /// <list type="bullet">
    ///   <item><description>
    ///     <b>-1 (default)</b> — auto-measure mode: a <c>ResizeObserver</c> measures the
    ///     container width on every resize and computes the maximum number of items that fit
    ///     before a "⋯" trigger button is needed. No consumer configuration required.
    ///   </description></item>
    ///   <item><description>
    ///     <b>Positive integer</b> — manual mode: exactly that many items are shown inline
    ///     and the rest collapse into the "⋯" dropdown regardless of available space.
    ///   </description></item>
    /// </list>
    /// </summary>
    [Parameter] public int VisibleCount { get; set; } = -1;

    /// <summary>aria-label for the "⋯" overflow button. Default: "More".</summary>
    [Parameter] public string? OverflowLabel { get; set; }

    /// <summary>
    /// Layout/keyboard orientation. Horizontal (default) uses Left/Right arrows
    /// to move between items; Vertical uses Up/Down. Drives <c>aria-orientation</c>.
    /// </summary>
    [Parameter] public ToolbarOrientation Orientation { get; set; } = ToolbarOrientation.Horizontal;

    private string OrientationStr => Orientation == ToolbarOrientation.Vertical ? "vertical" : "horizontal";

    // ── State ─────────────────────────────────────────────────────────────────

    private bool _overflowOpen;
    // rc.42: per-instance DOM id so the JS observer can `document.getElementById`
    // the toolbar without needing the ElementReference internal-id dance. Unique
    // per component instance so multiple Toolbars on a page don't share state.
    private readonly string _toolbarId = LumeoIds.New("lumeo-toolbar");

    // The id that ACTUALLY renders on the <div>: a consumer-splatted id in
    // AdditionalAttributes wins (it renders after the explicit id="@_toolbarId"
    // above), else the generated fallback. EVERY interop call below (roving
    // tabindex init, arrow-key prevent-default, overflow ResizeObserver, focus
    // movement) must target THIS, not the raw _toolbarId — otherwise a
    // consumer-supplied id (e.g. <Toolbar id="actions">) leaves those
    // registrations pointed at an id no element in the document carries, and
    // the toolbar silently loses its whole keyboard model: Arrow/Home/End fall
    // through to the browser default instead of roving focus, and
    // registerPreventDefaultKeys is a no-op lookup against a missing element
    // (PR #356 round-6, Codex P2). Mirrors Dock.razor's EffectiveElementId /
    // PopoverTrigger's EffectiveTriggerId.
    private string EffectiveToolbarId => LumeoIds.Effective(AdditionalAttributes, _toolbarId);

    // Auto-measurement (VisibleCount == -1 + Overflow == true)
    private bool _isObservingOverflow;
    // The id RegisterToolbarOverflow was ACTUALLY called with — registration
    // only ever happens once, on firstRender, so this just remembers that
    // exact id for a correctly-targeted unregister in DisposeAsync even if a
    // splatted id changes afterward (PR #356 round-6).
    private string? _registeredOverflowId;
    // The id the arrow-key prevent-default rule is ACTUALLY registered
    // against (null = not registered) — tracked by id, not a bool, so a
    // consumer-splatted id changing at runtime re-registers against the NEW
    // id instead of leaving the rule attached to a stale one that no longer
    // exists in the DOM (PR #356 round-6, Codex P2). Mirrors Dock's
    // _registeredPdId / PopoverTrigger's _registeredId.
    private string? _registeredPdId;
    // The Orientation the prevent-default rule set was ACTUALLY built for
    // (null = not registered yet). Compared against the CURRENT Orientation
    // below so the id-unchanged branch only unregisters/re-registers when the
    // key set truly needs to change, instead of on every render — without
    // this guard a Toolbar re-render with the same id (any parent/child state
    // update, not just an Orientation flip) paid two JS interop calls it
    // didn't need, worst on Blazor Server where each one is a round trip
    // (PR #356 round-9, Codex P3). Mirrors the registered-flag/id pattern
    // used throughout this file instead of a bare bool.
    private ToolbarOrientation? _registeredPdOrientation;
    private int _autoVisibleCount = -1; // -1 = not yet measured
    // Last total reported by the JS ResizeObserver. Persisted so OnParametersSet
    // can rebuild the auto-measure context with the REAL total instead of
    // int.MaxValue — otherwise an unrelated re-render would make the trigger
    // test (VisibleCount < TotalCount) true again and resurrect the empty "⋯".
    private int _autoTotalCount; // 0 = not yet measured

    private ToolbarOverflowContext _overflowCtx = new(ToolbarRenderSlot.Visible, -1, 0);
    private ToolbarOverflowContext _dropdownCtx = new(ToolbarRenderSlot.Dropdown, -1, 0);

    // ── Lifecycle ─────────────────────────────────────────────────────────────

    protected override void OnParametersSet()
    {
        if (!Overflow) return;

        // Effective visible count: prefer the explicit consumer value if > -1;
        // otherwise fall back to the JS-measured _autoVisibleCount.
        var effective = VisibleCount > -1 ? VisibleCount : _autoVisibleCount;

        // Manual mode (explicit VisibleCount) intentionally uses int.MaxValue as the
        // total so the trigger shows whenever items collapse past VisibleCount. In
        // auto-measure mode we MUST use the last measured total (_autoTotalCount) so a
        // re-render doesn't make VisibleCount < TotalCount true again and resurrect the
        // empty "⋯" trigger when everything already fits.
        var total = VisibleCount > -1 ? int.MaxValue : _autoTotalCount;

        _overflowCtx = new ToolbarOverflowContext(ToolbarRenderSlot.Visible, effective, total);
        _dropdownCtx = new ToolbarOverflowContext(ToolbarRenderSlot.Dropdown, effective, total);
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        // Make the toolbar a single tab stop with a roving tabindex over its
        // items (Radix Toolbar keyboard model). Runs in every mode, on EVERY
        // render — not just firstRender. Items added/removed/enabled after load
        // (e.g. a conditionally-rendered button, or one flipping disabled) would
        // otherwise never be re-managed, breaking the single-tab-stop invariant
        // (some items left with no tabindex are tab stops; the prior stop may be
        // gone). The JS init is idempotent and preserves the currently-focused
        // item as the stop, so re-running it after every render is safe and
        // re-establishes "exactly one tabindex=0" over the current item set —
        // including retracting the container's own tabindex="0" once real items
        // exist, so it never lingers as a second stop alongside the roving item.
        var effectiveId = EffectiveToolbarId;

        try { await Interop.InitToolbarRoving(effectiveId); }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }

        // Suppress the browser's native scroll for the orientation-aligned
        // navigation keys HandleKeyDown moves focus with (CodeRabbit P2:
        // Arrow/Home/End were moving roving focus AND scrolling the page).
        // Re-registered every render (idempotent — see registerPreventDefaultKeys)
        // so a runtime Orientation change keeps the rule set aligned.
        // SkipEditable (PR #356 round-3, Codex P2): an editable child (input/
        // textarea/contenteditable) nested in the toolbar owns Arrow/Home/End
        // itself for caret/selection movement — without this the JS listener
        // preventDefault'd those keys before the browser could move the caret,
        // and a child Blazor :stopPropagation can't stop this DOM-level listener.
        //
        // Targets effectiveId (not _toolbarId) and re-registers whenever it
        // changes at runtime — a consumer-splatted id renders over _toolbarId,
        // so registering against the raw fallback looks up an id no element
        // carries and the listener silently attaches to nothing (PR #356
        // round-6, Codex P2). Compared against the id ACTUALLY registered, not
        // just a bool, mirroring Dock's _registeredPdId.
        if (_registeredPdId != effectiveId)
        {
            try
            {
                if (_registeredPdId is not null)
                    await Interop.UnregisterPreventDefaultKeys(_registeredPdId);
                var navKeys = Orientation == ToolbarOrientation.Horizontal
                    ? new[] { "ArrowLeft", "ArrowRight", "Home", "End" }
                    : new[] { "ArrowUp", "ArrowDown", "Home", "End" };
                await Interop.RegisterPreventDefaultKeys(
                    effectiveId,
                    navKeys.Select(k => new Lumeo.Services.PreventDefaultKeyRule(k, SkipEditable: true)).ToArray());
                _registeredPdId = effectiveId;
                _registeredPdOrientation = Orientation;
            }
            catch (JSDisconnectedException) { }
            catch (ObjectDisposedException) { }
        }
        else if (_registeredPdOrientation != Orientation)
        {
            // Id unchanged, but Orientation flipped at runtime — the key set is
            // captured at registration time, so re-register in place to keep it
            // aligned (mirrors the pre-round-6 "every render" behavior for this
            // one case). Gated on the tracked Orientation (not just reached
            // unconditionally) so a same-id, same-Orientation re-render — the
            // common case, e.g. an unrelated parent/child state update — skips
            // the unregister/register round trip entirely instead of paying two
            // JS interop calls for a key set that didn't change (PR #356
            // round-9, Codex P3).
            try
            {
                await Interop.UnregisterPreventDefaultKeys(effectiveId);
                var navKeys = Orientation == ToolbarOrientation.Horizontal
                    ? new[] { "ArrowLeft", "ArrowRight", "Home", "End" }
                    : new[] { "ArrowUp", "ArrowDown", "Home", "End" };
                await Interop.RegisterPreventDefaultKeys(
                    effectiveId,
                    navKeys.Select(k => new Lumeo.Services.PreventDefaultKeyRule(k, SkipEditable: true)).ToArray());
                _registeredPdOrientation = Orientation;
            }
            catch (JSDisconnectedException) { }
            catch (ObjectDisposedException) { }
        }

        if (!firstRender) return; // overflow observer is wired once, on first render

        if (!Overflow || VisibleCount != -1) return; // manual mode — nothing else to wire up

        try
        {
            // 3.0: route through IComponentInteropService instead of a direct
            // IJSRuntime import. The service owns the toolbar.js module load
            // (cache-busted by assembly version) and dispatches measurement
            // callbacks back to us via OnOverflowMeasured. Targets effectiveId
            // for the same reason as every other call above (PR #356 round-6).
            await Interop.RegisterToolbarOverflow(effectiveId, OnOverflowMeasured);
            _isObservingOverflow = true;
            _registeredOverflowId = effectiveId;
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
    }

    // Radix Toolbar keyboard model: the orientation-aligned arrows move focus
    // between items (clamped, no wrap), Home/End jump to the first/last. The
    // perpendicular arrows are left to the browser so e.g. a vertical menu
    // inside a horizontal toolbar still works.
    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        var effectiveId = EffectiveToolbarId;
        var horizontal = Orientation == ToolbarOrientation.Horizontal;
        switch (e.Key)
        {
            case "ArrowRight" when horizontal:
            case "ArrowDown" when !horizontal:
                await Interop.MoveToolbarFocus(effectiveId, 1);
                break;
            case "ArrowLeft" when horizontal:
            case "ArrowUp" when !horizontal:
                await Interop.MoveToolbarFocus(effectiveId, -1);
                break;
            case "Home":
                await Interop.FocusToolbarEdge(effectiveId, last: false);
                break;
            case "End":
                await Interop.FocusToolbarEdge(effectiveId, last: true);
                break;
        }
    }

    /// <summary>
    /// Invoked (via <see cref="IComponentInteropService"/>) each time the JS
    /// ResizeObserver reports a new fitting count. Only triggers a re-render
    /// when the measured value actually changes.
    /// </summary>
    internal Task OnOverflowMeasured(int fittingCount, int totalCount)
    {
        // Always record the latest total so OnParametersSet can rebuild the
        // auto-measure context against it (a same-fitting re-measure may still
        // carry an updated total, and we must never fall back to int.MaxValue).
        _autoTotalCount = totalCount;

        if (fittingCount == _autoVisibleCount) return Task.CompletedTask; // no change — skip re-render

        _autoVisibleCount = fittingCount;

        _overflowCtx = new ToolbarOverflowContext(ToolbarRenderSlot.Visible, fittingCount, totalCount);
        _dropdownCtx = new ToolbarOverflowContext(ToolbarRenderSlot.Dropdown, fittingCount, totalCount);

        StateHasChanged();
        return Task.CompletedTask;
    }

    // ── Disposal ──────────────────────────────────────────────────────────────

    public async ValueTask DisposeAsync()
    {
        // Unregister from the id it was ACTUALLY registered under
        // (_registeredPdId / _registeredOverflowId), not the current
        // EffectiveToolbarId — a consumer-splatted id can change between
        // registration and disposal, and unregistering against the wrong id
        // would leave the stale listener attached (PR #356 round-6, mirrors
        // Dock's DisposeAsync).
        if (_registeredPdId is not null)
        {
            try { await Interop.UnregisterPreventDefaultKeys(_registeredPdId); }
            catch (JSDisconnectedException) { }
            catch (ObjectDisposedException) { }
        }
        try
        {
            if (_isObservingOverflow)
            {
                await Interop.UnregisterToolbarOverflow(_registeredOverflowId ?? _toolbarId);
            }
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
    }

    // ── CSS ──────────────────────────────────────────────────────────────────
    private string FlexDirection => Orientation == ToolbarOrientation.Vertical ? "flex-col" : "flex-row";

    private string CssClass =>
        Cx.Merge($"flex {FlexDirection} items-center gap-1 p-1 bg-card border border-border/40 rounded-lg", Class);

    private string CssClassOverflow =>
        Cx.Merge($"flex {FlexDirection} items-center gap-1 p-1 bg-card border border-border/40 rounded-lg overflow-hidden", Class);

    // ── Context record ────────────────────────────────────────────────────────

    /// <summary>Toolbar layout/keyboard orientation.</summary>
    public enum ToolbarOrientation { Horizontal, Vertical }

    /// <summary>Slot that a child item should render for in overflow mode.</summary>
    public enum ToolbarRenderSlot { Visible, Dropdown }

    /// <summary>
    /// Cascaded by <see cref="Toolbar"/> to all descendant items when overflow mode is active.
    /// Items use this to decide whether to render normally (Visible slot) or as a dropdown row
    /// (Dropdown slot), and whether to hide themselves when they fall past the VisibleCount boundary.
    /// </summary>
    public record ToolbarOverflowContext(ToolbarRenderSlot Slot, int VisibleCount, int TotalCount);
}

@namespace Lumeo

<div class="@CssClass" @attributes="AdditionalAttributes">
    @ChildContent
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("flex items-center gap-0.5", Class);
}

@namespace Lumeo

<div class="@CssClass" role="separator" aria-orientation="vertical" @attributes="AdditionalAttributes"></div>

@code {
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("w-px h-6 bg-border/40 mx-1 shrink-0", Class);
}

@namespace Lumeo

<div class="@CssClass" @attributes="AdditionalAttributes"></div>

@code {
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("flex-1", Class);
}
